function pageBasePath() {
  const path = window.location.pathname || "/";
  if (path.endsWith("/")) return path;
  return path.replace(/\/[^/]+$/, "/");
}

function opencvScriptUrl() {
  return pageBasePath() + "vendor/opencv/opencv.js";
}

function cvReady() {
  return globalThis.cv && globalThis.cv.Mat;
}

function ocrDiag(message) {
  const log = globalThis.__lotteryOcrDiag || (globalThis.__lotteryOcrDiag = []);
  const line = new Date().toISOString().slice(11, 19) + " opencv " + message;
  log.push(line);
  if (log.length > 100) log.shift();
}

function getProgressReporter(onProgress) {
  if (typeof onProgress === "function") return onProgress;
  if (typeof globalThis.__lotteryOpenCvOnProgress === "function") {
    return globalThis.__lotteryOpenCvOnProgress;
  }
  return null;
}

function reportOpenCvProgress(onProgress, message, percent) {
  const report = getProgressReporter(onProgress);
  if (report) report(message, percent);
}

function resolveDefaultExport(cv) {
  if (defaultResolve) {
    defaultResolve(cv);
    defaultResolve = null;
    defaultReject = null;
  }
}

function rejectDefaultExport(err) {
  if (defaultReject) {
    defaultReject(err);
    defaultResolve = null;
    defaultReject = null;
  }
}

function waitForCv(onProgress, timeoutMs) {
  return new Promise(function (resolve, reject) {
    const started = Date.now();
    let lastReport = 0;

    function step() {
      if (cvReady()) {
        ocrDiag("cv.Mat ready");
        resolveDefaultExport(globalThis.cv);
        reportOpenCvProgress(onProgress, "OpenCV 就绪", 42);
        resolve(globalThis.cv);
        return;
      }
      const elapsed = Date.now() - started;
      if (elapsed > timeoutMs) {
        ocrDiag("timeout " + String(elapsed) + "ms");
        reject(
          new Error("OpenCV 初始化超时（WASM 编译较慢，请换 WiFi 或刷新重试）")
        );
        return;
      }
      if (elapsed - lastReport >= 2000) {
        lastReport = elapsed;
        const sec = Math.round(elapsed / 1000);
        reportOpenCvProgress(
          onProgress,
          "OpenCV WASM 编译中，已等待 " + sec + " 秒...",
          41
        );
        ocrDiag("waiting " + sec + "s hasCv=" + String(!!globalThis.cv));
      }
      setTimeout(step, 200);
    }

    step();
  });
}

let openCvPromise = null;
let defaultResolve = null;
let defaultReject = null;

const defaultExport = new Promise(function (resolve, reject) {
  defaultResolve = resolve;
  defaultReject = reject;
});

export function resetOpenCvLoad() {
  openCvPromise = null;
  globalThis.__lotteryOpenCvPromise = null;
}

export function loadOpenCv(onProgress) {
  if (cvReady()) {
    ocrDiag("already ready");
    resolveDefaultExport(globalThis.cv);
    reportOpenCvProgress(onProgress, "OpenCV 就绪", 42);
    return Promise.resolve(globalThis.cv);
  }

  if (openCvPromise) {
    ocrDiag("reuse in-flight promise");
    return openCvPromise;
  }

  const url = opencvScriptUrl();
  ocrDiag("load start " + url);
  openCvPromise = new Promise(function (resolve, reject) {
    if (document.querySelector('script[data-lottery-opencv="1"]')) {
      ocrDiag("existing script tag");
      waitForCv(onProgress, 180000).then(resolve, reject);
      return;
    }

    reportOpenCvProgress(onProgress, "正在加载 OpenCV（约 10MB）...", 37);

    const script = document.createElement("script");
    script.src = url;
    script.dataset.lotteryOpencv = "1";
    script.onerror = function () {
      ocrDiag("script onerror");
      reject(new Error("OpenCV 脚本加载失败"));
    };
    script.onload = function () {
      ocrDiag("script onload cv=" + String(cvReady()));
      reportOpenCvProgress(
        onProgress,
        "OpenCV WASM 编译中，首次约需 30-60 秒，请勿关闭...",
        41
      );
      waitForCv(onProgress, 180000).then(resolve, reject);
    };
    document.head.appendChild(script);
  })
    .catch(function (err) {
      openCvPromise = null;
      globalThis.__lotteryOpenCvPromise = null;
      rejectDefaultExport(err);
      ocrDiag("load fail " + String((err && err.message) || err));
      throw err;
    });

  globalThis.__lotteryOpenCvPromise = openCvPromise;
  return openCvPromise;
}

export default defaultExport;
